// Original code.org Game Lab source. This is the high-fidelity reference;
// the TypeScript port should reproduce its behavior exactly before any
// gameplay refactors. Do not edit this file — treat it as a frozen spec.

var backGround = createSprite(200, 200, 400, 400);
backGround.setAnimation("space_1");
drawSprites();
var UFO1 = createSprite(100, 200, 0.1, 0.1);
var UFO2 = createSprite(100, 200, 0.1, 0.1);
var blocks = [];
UFO1.scale = 0.1;
UFO2.scale = 0.1;
var count = 0;
var health = 10;
var points = 0;
var coinExists = false;
var coin = createSprite(-100, -100);
var difficulty = -2;
var winCon = 25;
var players = 1;
// Create an array of all the retroship animation names
var shipAnimations = [];
for (var i = 1; i <= 21; i++) {
  var animationName;
  if (i < 10) {
    animationName = "retroship_0" + i + "_1";
  } else {
    animationName = "retroship_" + i + "_1";
  }
  shipAnimations.push(animationName);
}
playSound("sound://category_music/clear_evidence_loop1.mp3", true);

function draw() {
  if (health > 0 && points < winCon && difficulty > 0) {
    backGround.setAnimation("space_1");
    UFO1.setAnimation("ufo_1");
    UFO2.setAnimation("ufo_2");

    drawSprite(backGround);
    if (keyWentDown("up")) {
      UFO1.velocityY = -12;
    }
     if (keyWentDown("w")) {
      UFO2.velocityY = -12;
    }
    UFO1.velocityX = 0;
    UFO2.velocityX = 0;
    if(keyDown("left")) {UFO1.velocityX = -5}
    if(keyDown("right")) {UFO1.velocityX = 5}
    if(keyDown("a")) {UFO2.velocityX = -5}
    if(keyDown("d")) {UFO2.velocityX = 5}
    UFO2.velocityY += 1.5;
    UFO1.velocityY += 1.5;
    drawSprites();
    textSize(20);
    fill("red");
    text("Health: " + health, 300, 20);
    fill("green");
    text("Points: " + points, 300, 50);
    count++;
    // Create a new block with a random retroship animation every 50 frames
    if (count === 100 - (difficulty * 25)) {
     // Create a new sprite at (0, 0)
var newBlock = createSprite(0, 0);

// Assign a random number from 1 to 4 to the `direction` property of the new sprite
newBlock.direction = randomNumber(1, 4);

// The initial scale of the sprite is 0.3, regardless of its direction
newBlock.scale = 0.2;

// If the direction is 1, set its initial position and velocity
if (newBlock.direction === 1) {
    newBlock.velocityX = -5;
    newBlock.x = 410; // Start offscreen on the right edge
    newBlock.y = randomNumber(10, 390);
}
// If the direction is 2, set its initial position and velocity
if (newBlock.direction === 2) {
    newBlock.velocityY = -5;
    newBlock.y = 410; // Start offscreen on the bottom edge
    newBlock.x = randomNumber(10, 390);
}
// If the direction is 3, set its initial position and velocity
if (newBlock.direction === 3) {
    newBlock.velocityX = 5;
    newBlock.x = -10; // Start offscreen on the left edge
    newBlock.y = randomNumber(10, 390);
}
// If the direction is 4, set its initial position and velocity
if (newBlock.direction === 4) {
    newBlock.velocityY = 5;
    newBlock.y = -10; // Start offscreen on the top edge
    newBlock.x = randomNumber(10, 390);
}
      // Get a random index from the shipAnimations array (0 to 20)
      var randomIndex = randomNumber(0, shipAnimations.length - 1);
      // Set the block's animation to the randomly selected one
      newBlock.setAnimation(shipAnimations[randomIndex]);

      blocks.push(newBlock);
      count = 0;
    }
if(!coinExists) {
coin.setAnimation("coin");
coin.y = randomNumber(50, 350);
coin.x = randomNumber(50, 350);
coinExists = true;
coin.scale = 0.4;
}
if(UFO1.isTouching(coin) || (UFO2.isTouching(coin) && players === 3)) {
  points++;
  coinExists = false;
  coin.y = 500;
}
    // Check blocks for scoring or off-screen removal
    for (var i = blocks.length - 1; i >= 0; i--) {
      var currentBlock = blocks[i];

      // Check if the block went off-screen
      if (currentBlock && currentBlock.x < -10) {
        currentBlock.destroy();
        blocks.splice(i, 1);
      }
    }

    // Damage logic for wall collision
    if (UFO1.y < 0 || UFO1.y > 400 || UFO1.x < 0 || UFO1.x > 400) {
      handleDamage();
    }
    if ((UFO2.y < 0 || UFO2.y > 400 || UFO2.x < 0 || UFO2.x > 400) && players === 3) {
      handleDamage();
    }
    // Damage logic for block collision
    for (var i = 0; i < blocks.length; i++) {
      var currentBlockB = blocks[i];
      if (UFO1.isTouching(currentBlockB) || UFO2.isTouching(currentBlockB) && players == 3) {
        handleDamage();
      }
    }
  } else {
    if(health === 0) {
    background("black");

    fill("red");
    textSize(70);
    textAlign(CENTER, CENTER);
    text("Game Over!", 200, 150);

    textSize(20);
    text("Your score: " + points, 200, 250);
    text("press R to restart", 199, 300);
  }
  else if(points === winCon) {
    fill("green");
    textSize(70);
    textAlign(CENTER, CENTER);
    text("You Win!", 200, 150);

    textSize(20);
    text("Final Health: " + health, 200, 250);
    text("press C to keep going!", 200, 275);
    if(keyWentDown("C")) {
      winCon += 25;
      health++;
    }
  } else if (difficulty === -1) {
    backGround.setAnimation("space_1");
    fill("white");
    drawSprites();
    textSize(50);
    text("Select difficulty:", 20, 100);
    textSize(20);
    fill("green");
    text("press 1 for easy", 100, 150);
    fill("yellow");
    text("press 2 for normal", 100, 200);
    fill("red");
    text("press 3 for hard", 100, 250);
    fill("white");
    textSize(15);
    text("Game designed and coded by Hyrum Adams", 50, 300);
    if(players === 1) {
      UFO2.y = -10000;
    }
    if(keyWentDown("1")) {
      difficulty = 1;
    }
        if(keyWentDown("2")) {
      difficulty = 2;
    }
        if(keyWentDown("3")) {
      difficulty = 3;
    }
  } else if (difficulty === -2) {
  background("black");
  textAlign(LEFT, TOP);

  // Title
  textSize(40);
  fill("white");
  text("🚀 UFO Survival", 60, 30);

  // --- Create small sprite previews ---
  // (We'll position them each frame, so they don't vanish or duplicate)

  // UFO1 (player)
  if (!this.UFOIcon) {
    this.UFOIcon = createSprite(50, 160);
    this.UFOIcon.setAnimation("ufo_1");
    this.UFOIcon.scale = 0.08;
  }
  if (!this.UFO2Icon) {
    this.UFO2Icon = createSprite(50, 190);
    this.UFO2Icon.setAnimation("ufo_2");
    this.UFO2Icon.scale = 0.08;
  }

  // Coin
  if (!this.coinIcon) {
    this.coinIcon = createSprite(50, 250);
    this.coinIcon.setAnimation("coin");
    this.coinIcon.scale = 0.4;
  }

  // Enemy ship
  if (!this.enemyIcon) {
    this.enemyIcon = createSprite(50, 220);
    this.enemyIcon.setAnimation("retroship_02_1");
    this.enemyIcon.scale = 0.08;
  }

  // --- Text Instructions ---
  textSize(20);
  fill("lightblue");
  text("Controls:", 50, 120);
  fill("white");
  text("- Arrow keys to move (1st player)", 70, 150);
  text("- Use WASD to move (2nd player)", 70, 180);
  text("- Avoid enemy ships!", 70, 210);
  text("- Collect coins for points", 70, 240);
  text("- If your health reaches 0, you lose.", 70, 270);

  fill("yellow");
  text("Goal: Get " + winCon + " points to win!", 60, 310);

  fill("orange");
  textSize(18);
  text("Press SPACE for one player", 70, 350);
  text("Press BACKSPACE for two player!", 50, 370);

  drawSprite(this.UFOIcon);
  drawSprite(this.UFO2Icon);
  drawSprite(this.coinIcon);
  drawSprite(this.enemyIcon);
  drawSprite(this.healthIcon);

  // --- Transition ---
  if (keyWentDown("space")) {
    // Destroy icons when leaving screen
    this.UFOIcon.destroy();
    this.UFO2Icon.destroy();
    this.coinIcon.destroy();
    this.enemyIcon.destroy();
    this.UFOIcon = this.coinIcon = this.enemyIcon = this.healthIcon = null;
    difficulty = -1;
  }
  if (keyWentDown("backspace")) {
    // Destroy icons when leaving screen
    this.UFOIcon.destroy();
    this.UFO2Icon.destroy();
    this.coinIcon.destroy();
    this.enemyIcon.destroy();
    this.UFOIcon = this.coinIcon = this.enemyIcon = this.healthIcon = null;
    difficulty = -1;
    players = 3;
}

}
if(keyWentDown("r")) {
  health = 11;
  points = 0;
   UFO1.y = 600;
   UFO1.velocityY = 0;
   UFO1.velocityX = 0;
   if(players > 2) {
   UFO2.y = 600;
   UFO2.velocityY = 0;
   UFO2.velocityX = 0;
   }
  background(rgb(255, 0, 0, 0.5));
  winCon = 25;
  for (var i = 0; i < blocks.length; i++) {
    if (blocks[i]) {
      blocks[i].destroy();
    }
  }
  blocks = [];
  difficulty = -1;
}
}

function handleDamage() {
  health--;
  UFO1.y = 200;
  UFO1.x = 200;
  UFO1.velocityY = -15;
  if(players > 2) {
  UFO2.y = 200;
  UFO2.x = 200;
  UFO2.velocityY = -15;
  }
  background(rgb(255, 0, 0, 0.5));

  for (var i = 0; i < blocks.length; i++) {
    if (blocks[i]) {
      blocks[i].destroy();
    }
  }
  blocks = [];
}
}
